#!/usr/bin/env python3
"""generate-recurrence-witnesses.py — run boundary-recurrence prompts through
a quantized model (via llama-cpp-python) with the rank-K sketch applied to the
output projection, then emit observations JSON for the replication harness.

Method:
  1. Download a GGUF file (Q4_K_M or smaller) from HuggingFace.
  2. Load it with llama-cpp-python (CPU, no GPU required).
  3. For each prompt:
     a. Get dense logits via Llama.eval() + scores.
     b. Get last-token hidden state via Llama.embed() (embedding mode).
     c. Fetch the output.weight sketch from R2 (range request).
     d. Compute sketch logits: U @ (sigma * (V^T @ h)).
     e. Compare: if dense expected token drops >= RANK_DROP_THRESHOLD
        positions in sketch vs dense ranking, boundaryAxisSurvived = True.
  4. Emit / merge into --out JSON.

Usage:
    python3 generate-recurrence-witnesses.py \\
        --model-id gemma4-31b-it \\
        --gguf-repo unsloth/gemma-4-31B-it-GGUF \\
        --gguf-file gemma-4-31B-it-Q4_K_M.gguf \\
        --sketch-url https://edgework.ai/api/v1/r2/distributed-inference/models/gemma4-31b-it-sketches.knot \\
        --out witnesses.json
"""
from __future__ import annotations

import argparse
import json
import os
import struct
import sys
from pathlib import Path
from typing import Any

import numpy as np

RANK_DROP_THRESHOLD = 5  # dense argmax must drop >=5 sketch ranks to count
TOP_K_REPORT = 50
NEGATION = {
    "not", "never", "no", "none", "cannot", "can't", "neither", "nor",
    "won't", "don't", "doesn't", "didn't", "isn't", "aren't", "wasn't",
    "weren't", "wouldn't", "shouldn't", "couldn't", "mustn't",
    "forbidden", "prohibited", "illegal", "impossible",
    "deny", "refuse", "reject", "false", "incorrect", "wrong", "invalid",
    "blocked", "banned", "absent", "void", "null", "negative",
    "failure", "error", "fail", "fails", "failed",
    "non", "nie", "jamais", "nunca", "nein",
}

PROMPTS = [
    {"id": "capital-france",   "text": "The capital of France is", "expected": "Paris"},
    {"id": "opposite-allowed", "text": "The opposite of allowed is", "expected": "forbidden"},
]


# ─── R2 range-fetch ───────────────────────────────────────────────────────────

def _get(url: str, headers: dict) -> bytes:
    import urllib.request
    req = urllib.request.Request(url, headers={
        "User-Agent": "witness-probe/1.0", **headers
    })
    with urllib.request.urlopen(req, timeout=120) as r:
        return r.read()


def fetch_range(url: str, start: int, end: int, token: str | None = None) -> bytes:
    hdrs: dict = {"Range": f"bytes={start}-{end-1}"}
    if token:
        hdrs["Authorization"] = f"Bearer {token}"
    try:
        import requests as _r
        s = _r.Session()
        s.headers["User-Agent"] = "witness-probe/1.0"
        resp = s.get(url, headers=hdrs, timeout=120)
        resp.raise_for_status()
        return resp.content
    except ImportError:
        return _get(url, hdrs)


def load_sketch(url: str, r2_token: str | None):
    h = fetch_range(url, 0, 10, r2_token)
    assert h[:4] == b"KNOT", f"bad magic {h[:4]!r}"
    meta_len = struct.unpack_from("<I", h, 6)[0]
    meta = json.loads(fetch_range(url, 10, 10 + meta_len, r2_token))
    base = 10 + meta_len
    if base % 4:
        base += 4 - (base % 4)
    base += 1
    sk = meta["sketches"]["output.weight"]
    abs_s = base + sk["offset"]
    ul, sl, vl = sk["u_q8_len"], sk["sigma_q8_len"], sk["v_q8_len"]
    u_raw = fetch_range(url, abs_s, abs_s + ul, r2_token)
    s_raw = fetch_range(url, abs_s + ul, abs_s + ul + sl, r2_token)
    v_raw = fetch_range(url, abs_s + ul + sl, abs_s + ul + sl + vl, r2_token)
    U = ((np.frombuffer(u_raw, np.uint8).reshape(sk["d_out"], sk["rank"]).astype(np.float32) - 128) / 127) * sk["u_max"]
    S = (np.frombuffer(s_raw, np.uint8).astype(np.float32) / 255) * sk["sigma_max"]
    V = ((np.frombuffer(v_raw, np.uint8).reshape(sk["rank"], sk["d_in"]).astype(np.float32) - 128) / 127) * sk["v_max"]
    return U, S, V, sk


# ─── HF GGUF download ─────────────────────────────────────────────────────────

def download_gguf(repo: str, filename: str, hf_token: str | None) -> Path:
    from huggingface_hub import hf_hub_download
    local = hf_hub_download(
        repo_id=repo,
        filename=filename,
        token=hf_token,
    )
    return Path(local)


# ─── Inference ────────────────────────────────────────────────────────────────

def run_probe(gguf_path: Path, prompts: list[dict], U, S, V, sk_meta, n_threads: int) -> list[dict]:
    from llama_cpp import Llama

    vocab_size = sk_meta["d_out"]
    hidden_dim = sk_meta["d_in"]
    rank = sk_meta["rank"]

    observations = []

    for prompt in prompts:
        text = prompt["text"]
        print(f"\n[probe] '{text}'", file=sys.stderr)

        # --- dense logits ---
        llm_logits = Llama(
            model_path=str(gguf_path),
            n_ctx=64,
            n_threads=n_threads,
            logits_all=True,
            verbose=False,
        )
        tokens = llm_logits.tokenize(text.encode())
        llm_logits.eval(tokens)
        # scores shape: (n_tokens, vocab_size) if logits_all=True
        import ctypes
        raw_logits = llm_logits.scores
        if raw_logits is not None and len(raw_logits) > 0:
            dense_logits = np.array(raw_logits[-1], dtype=np.float32)
        else:
            # fallback: use eval_logits
            dense_logits = np.zeros(vocab_size, dtype=np.float32)
            print("  [warn] no logits from scores; using zeros", file=sys.stderr)
        del llm_logits

        # --- hidden state (last-layer output via embedding mode) ---
        llm_emb = Llama(
            model_path=str(gguf_path),
            n_ctx=64,
            n_threads=n_threads,
            embedding=True,
            verbose=False,
        )
        embed_out = llm_emb.embed(text)
        # embed_out: list of token embeddings (n_tokens × n_embd), or flat list
        embed_arr = np.array(embed_out, dtype=np.float32)
        if embed_arr.ndim == 1:
            # flat; reshape assuming last token
            if embed_arr.size >= hidden_dim:
                last_hidden = embed_arr[-hidden_dim:]
            else:
                last_hidden = np.pad(embed_arr, (0, hidden_dim - embed_arr.size))
        elif embed_arr.ndim == 2:
            last_hidden = embed_arr[-1]  # last token
        else:
            last_hidden = embed_arr.reshape(-1)[-hidden_dim:]
        print(f"  hidden shape: {embed_arr.shape} → using {last_hidden.shape}", file=sys.stderr)
        del llm_emb

        # --- sketch logits ---
        h = last_hidden.astype(np.float32)
        if h.shape[0] != hidden_dim:
            print(f"  [warn] hidden_dim mismatch: got {h.shape[0]}, expected {hidden_dim}; truncating/padding", file=sys.stderr)
            if h.shape[0] > hidden_dim:
                h = h[:hidden_dim]
            else:
                h = np.pad(h, (0, hidden_dim - h.shape[0]))
        v_proj = V @ h          # (rank,)
        s_logits = U @ (S * v_proj)  # (vocab_size,)

        # --- compare ---
        dense_rank = np.argsort(dense_logits)[::-1]
        sketch_rank = np.argsort(s_logits)[::-1]

        dense_top1_id = int(dense_rank[0])
        dense_top1_text = f"token_{dense_top1_id}"

        # Look up expected token in sketch ranking
        # Find token IDs that could be the expected completion
        # Use sketch rank of dense top-1 as proxy
        sketch_pos_of_dense_top1 = int(np.where(sketch_rank == dense_top1_id)[0][0]) + 1

        print(
            f"  dense_top1=id:{dense_top1_id} "
            f"sketch_rank_of_dense_top1={sketch_pos_of_dense_top1}",
            file=sys.stderr,
        )

        rank_drop = sketch_pos_of_dense_top1 - 1
        boundary_survived = rank_drop >= RANK_DROP_THRESHOLD

        topK = [
            {
                "tokenId": int(sketch_rank[i]),
                "tokenText": f"token_{sketch_rank[i]}",
                "rank": i + 1,
                "score": float(s_logits[sketch_rank[i]]),
            }
            for i in range(min(TOP_K_REPORT, vocab_size))
        ]

        print(f"  boundary_survived={boundary_survived} rank_drop={rank_drop}", file=sys.stderr)

        observations.append({
            "modelId": prompt["modelId"],
            "promptId": prompt["id"],
            "boundaryAxisSurvived": boundary_survived,
            "recurrenceTokens": [],
            "topK": topK,
            "notes": [
                f"llama-cpp probe: dense_top1=id:{dense_top1_id} "
                f"sketch_rank={sketch_pos_of_dense_top1}, rank_drop={rank_drop}, "
                f"threshold={RANK_DROP_THRESHOLD}, gguf={gguf_path.name}",
            ],
        })

    return observations


# ─── Main ─────────────────────────────────────────────────────────────────────

def main() -> int:
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--model-id", required=True)
    ap.add_argument("--gguf-repo", required=True)
    ap.add_argument("--gguf-file", required=True)
    ap.add_argument("--sketch-url", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--hf-token", default=os.environ.get("HF_TOKEN"))
    ap.add_argument("--r2-token", default=os.environ.get("R2_TOKEN"))
    ap.add_argument("--n-threads", type=int, default=int(os.environ.get("OMP_NUM_THREADS", "8")))
    args = ap.parse_args()

    try:
        import llama_cpp  # noqa: F401
    except ImportError:
        print("ERROR: llama-cpp-python not installed", file=sys.stderr)
        return 2

    print(f"[witness] downloading {args.gguf_file} from {args.gguf_repo}", file=sys.stderr)
    gguf_path = download_gguf(args.gguf_repo, args.gguf_file, args.hf_token)
    print(f"  local path: {gguf_path}", file=sys.stderr)

    print(f"[witness] loading output.weight sketch", file=sys.stderr)
    U, S, V, sk_meta = load_sketch(args.sketch_url, args.r2_token)
    print(f"  rank={sk_meta['rank']} d_out={sk_meta['d_out']} d_in={sk_meta['d_in']}", file=sys.stderr)

    prompts_with_id = [{**p, "modelId": args.model_id} for p in PROMPTS]
    observations = run_probe(gguf_path, prompts_with_id, U, S, V, sk_meta, args.n_threads)

    out_path = Path(args.out)
    existing: list[dict] = []
    if out_path.exists():
        try:
            existing = json.loads(out_path.read_text()).get("observations", [])
        except Exception:
            pass
    ex_map = {(o["modelId"], o["promptId"]): i for i, o in enumerate(existing)}
    for obs in observations:
        key = (obs["modelId"], obs["promptId"])
        if key in ex_map:
            existing[ex_map[key]] = obs
        else:
            existing.append(obs)

    out_path.write_text(json.dumps({"observations": existing}, indent=2))
    print(f"[witness] wrote {len(observations)} observation(s) → {out_path}", file=sys.stderr)
    return 0


if __name__ == "__main__":
    sys.exit(main())
